package it.unimol.gestione_esami.service;import it.unimol.gestione_esami.dto.ExamCalendarDTO;import it.unimol.gestione_esami.dto.ExamDTO;import it.unimol.gestione_esami.dto.converter.ExamCalendarConverter;import it.unimol.gestione_esami.dto.converter.ExamConverter;import it.unimol.gestione_esami.dto.request.CreateExamRequest;import it.unimol.gestione_esami.dto.request.UpdateExamRequest;import it.unimol.gestione_esami.entity.ClassroomCache;import it.unimol.gestione_esami.entity.CourseCache;import it.unimol.gestione_esami.entity.Exam;import it.unimol.gestione_esami.entity.UserCache;import it.unimol.gestione_esami.enums.ExamStatus;import it.unimol.gestione_esami.exception.BusinessException;import it.unimol.gestione_esami.exception.ResourceNotFoundException;import it.unimol.gestione_esami.messaging.ExamEventPublisher;import it.unimol.gestione_esami.repository.ClassroomCacheRepository;import it.unimol.gestione_esami.repository.CourseCacheRepository;import it.unimol.gestione_esami.repository.ExamRepository;import it.unimol.gestione_esami.repository.UserCacheRepository;import jakarta.transaction.Transactional;import org.springframework.stereotype.Service;import java.time.LocalDate;import java.util.List;import java.util.stream.Collectors;@Service@Transactionalpublic class ExamService {    private final ExamRepository examRepository;    private final ExamConverter examConverter;    private final ExamCalendarConverter examCalendarConverter;    private final ExamEventPublisher eventPublisher;    private final CourseCacheRepository courseCacheRepository;    private final ClassroomCacheRepository classroomCacheRepository;    private final UserCacheRepository userCacheRepository;    public ExamService(ExamRepository examRepository, ExamConverter examConverter, ExamCalendarConverter examCalendarConverter,                       ExamEventPublisher eventPublisher, CourseCacheRepository courseCacheRepository,                       ClassroomCacheRepository classroomCacheRepository, UserCacheRepository userCacheRepository) {        this.examRepository = examRepository;        this.examConverter = examConverter;        this.examCalendarConverter = examCalendarConverter;        this.eventPublisher = eventPublisher;        this.courseCacheRepository = courseCacheRepository;        this.classroomCacheRepository = classroomCacheRepository;        this.userCacheRepository = userCacheRepository;    }    public List<ExamDTO> getAllExams() {        return examRepository.findAll()                .stream()                .map(examConverter::toDto)                .collect(Collectors.toList());    }    public ExamDTO getExamById(Long id) {        return examRepository.findById(id)                .map(examConverter::toDto)                .orElseThrow(() -> new ResourceNotFoundException("Esame non trovato con questo ID: " + id));    }    public ExamDTO createExam(CreateExamRequest request) {        Exam exam = new Exam();        exam.setName(request.getName());        exam.setDate(request.getDate());        exam.setTime(request.getTime());        exam.setCourseId(request.getCourseId());        exam.setProfessorId(request.getProfessorId());        exam.setClassroomId(request.getClassroomId());        CourseCache course = courseCacheRepository.findByCourseId(request.getCourseId());        if (course != null) {            exam.setCourseName(course.getCourseName());        }        ClassroomCache classroom = classroomCacheRepository.findByClassroomId(request.getClassroomId());        if (classroom != null) {            exam.setClassroomName(classroom.getClassroomName());        }        UserCache professor = userCacheRepository.findByUserId(request.getProfessorId());        if (professor != null) {            exam.setProfessorName(professor.getFullName());        }        exam.setMaxStudents(request.getMaxStudents());        exam.setEnrollmentDeadline(request.getEnrollmentDeadline());        exam.setStatus(ExamStatus.SCHEDULED);        exam.setNotes(request.getNotes());        Exam saved = examRepository.save(exam);        eventPublisher.publishExamCreated(examConverter.toDto(saved));        return examConverter.toDto(saved);    }    public ExamDTO updateExam(Long id, UpdateExamRequest request) {        Exam exam = examRepository.findById(id)                .orElseThrow(() -> new ResourceNotFoundException("Esame non trovato con id:" + id));        exam.setName(request.getName());        exam.setDate(request.getDate());        exam.setTime(request.getTime());        exam.setCourseId(request.getCourseId());        exam.setProfessorId(request.getProfessorId());        exam.setClassroomId(request.getClassroomId());        exam.setMaxStudents(request.getMaxStudents());        exam.setEnrollmentDeadline(request.getEnrollmentDeadline());        exam.setNotes(request.getNotes());        Exam saved = examRepository.save(exam);        eventPublisher.publishExamUpdated(examConverter.toDto(saved));        return examConverter.toDto(saved);    }    public void deleteExam(Long id) {        Exam exam = examRepository.findById(id)                        .orElseThrow(() -> new ResourceNotFoundException("Esame non trovato con id:" + id));        if(exam.getCurrentEnrollments() > 0){            throw new BusinessException("Impossibile cancellare l'esame con iscrizioni attive");        }        eventPublisher.publishExamDeleted(id);        examRepository.deleteById(id);    }    public List<ExamDTO> getExamsByCourse(Long courseId) {        return examRepository.findByCourseId(courseId)                .stream()                .map(examConverter::toDto)                .collect(Collectors.toList());    }    public List<ExamDTO> getExamsByProfessor(Long professorId) {        return examRepository.findByProfessorId(professorId)                .stream()                .map(examConverter::toDto)                .collect(Collectors.toList());    }    public List<ExamCalendarDTO> getExamCalendar() {        return examRepository.findAll()                .stream()                .filter(e -> e.getStatus() == ExamStatus.SCHEDULED                        || e.getStatus() == ExamStatus.ONGOING)                .map(examCalendarConverter::toDto)                .collect(Collectors.toList());    }    public List<ExamDTO> getAvailableExams() {        LocalDate today = LocalDate.now();        return examRepository.findAll()                .stream()                .filter(e -> e.getStatus() == ExamStatus.SCHEDULED                        && e.getEnrollmentDeadline() != null                        && !e.getEnrollmentDeadline().isBefore(today))                .map(examConverter::toDto)                .collect(Collectors.toList());    }}